INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (1, 'fr', 'Curcumine. Colorant jaune naturel issu du curcuma. Sans danger. Possède des propriétés anti-inflammatoires. Utilisé dans la moutarde et les produits au curry.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (2, 'fr', 'Riboflavine (Vitamine B2). Colorant jaune-orangé naturel. Sans danger et nutritif. Présent dans de nombreux aliments.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (3, 'fr', 'Tartrazine. Colorant jaune synthétique. Peut provoquer de l''hyperactivité chez les enfants. Peut déclencher des réactions allergiques. Soumis à des exigences d''étiquetage.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (4, 'fr', 'Chrysoïne - colorant jaune-orangé synthétique. INTERDIT dans de nombreux pays dont l''UE. Ne devrait pas être commercialisé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (5, 'fr', 'Jaune de quinoléine. Colorant synthétique. Peut provoquer de l''hyperactivité chez les enfants. Interdit dans certains pays. À éviter en cas de sensibilité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (6, 'fr', 'Jaune rapide - colorant azoïque. INTERDIT dans l''UE et aux États-Unis. Cancérogène possible. Non autorisé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (8, 'fr', 'Jaune 2G - colorant azoïque. INTERDIT dans l''UE depuis 2007 pour risques génotoxiques. Ne pas utiliser.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (9, 'fr', 'Jaune orangé S. Colorant azoïque. Peut provoquer de l''hyperactivité chez les enfants et des réactions allergiques. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (10, 'fr', 'Cochenille (Carmin). Colorant rouge naturel issu d''insectes. Peut provoquer des réactions allergiques sévères. Non adapté aux végétariens.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (11, 'fr', 'Orcéine - colorant rouge. INTERDIT dans l''UE. Cancérogène potentiel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (12, 'fr', 'Carmoisine. Colorant rouge synthétique. Peut provoquer de l''hyperactivité chez les enfants. Peut déclencher de l''asthme. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (13, 'fr', 'Amarante - colorant rouge azoïque. INTERDIT aux États-Unis depuis 1976 (cancérogène suspecté). Dans l''UE autorisé uniquement pour le caviar. ÉVITER.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (14, 'fr', 'Ponceau 4R. Colorant rouge synthétique. Peut provoquer de l''hyperactivité chez les enfants. Lié à des réactions allergiques. Interdit aux États-Unis et en Norvège.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (15, 'fr', 'Ponceau SX - colorant rouge. INTERDIT dans de nombreux pays dont l''UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (16, 'fr', 'Ponceau 6R - colorant rouge azoïque. INTERDIT dans l''UE et aux États-Unis. Cancérogène suspecté.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (17, 'fr', 'Érythrosine - colorant rouge contenant de l''iode. Possible perturbateur thyroïdien et cancérogène suspecté. Interdit dans de nombreux pays. ÉVITER.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (19, 'fr', 'Rouge Allura. Colorant rouge synthétique. Peut provoquer de l''hyperactivité chez les enfants. Allergène possible. Très utilisé aux États-Unis.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (20, 'fr', 'Bleu d''indanthrène - colorant synthétique. INTERDIT dans l''UE. Ne pas utiliser.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (21, 'fr', 'Bleu patenté V. Colorant bleu synthétique. Peut provoquer des réactions allergiques. Interdit dans plusieurs pays dont les États-Unis et l''Australie.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (22, 'fr', 'Indigotine (Carmin d''indigo). Colorant bleu synthétique. Peut provoquer des nausées et de l''hypertension. Allergène possible.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (23, 'fr', 'Bleu brillant FCF. Colorant bleu synthétique. Généralement sans danger mais peut provoquer des réactions allergiques chez les personnes sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (24, 'fr', 'Chlorophylles - colorant vert naturel extrait de plantes. Totalement sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (25, 'fr', 'Complexes cuivriques de chlorophylles - dérivés de chlorophylle stabilisés au cuivre. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (26, 'fr', 'Vert S/Vert brillant acide - colorant vert synthétique. Approuvé par l''EFSA mais interdit dans certains pays (Canada, États-Unis, Japon). Possibles réactions allergiques rares.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (27, 'fr', 'Caramel ordinaire. Colorant brun naturel. Généralement sans danger. Très utilisé dans les boissons gazeuses et les sauces.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (29, 'fr', 'Caramel ammoniacal. Colorant brun. Peut contenir des traces d''ammoniac. Généralement reconnu comme sûr en petites quantités.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (30, 'fr', 'Caramel au sulfite d''ammonium. Caramel le plus utilisé. Contient des sulfites - peut provoquer des réactions chez les asthmatiques. Courant dans les boissons au cola.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (31, 'fr', 'Noir brillant BN - colorant noir azoïque. Allergies possibles. Interdit dans de nombreux pays (États-Unis, Canada, Japon). À limiter.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (32, 'fr', 'Noir de carbone 7984 - colorant noir issu du charbon. INTERDIT dans l''UE pour raisons de sécurité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (33, 'fr', 'Charbon végétal - colorant noir issu de la combustion de plantes. CONTROVERSÉ, peut interférer avec les médicaments.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (34, 'fr', 'Brun FK - colorant brun synthétique. Approuvé dans l''UE mais interdit dans de nombreux autres pays. À utiliser avec prudence.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (35, 'fr', 'Brun HT/Brun chocolat - colorant brun synthétique. Approuvé par l''EFSA mais interdit dans certains pays (États-Unis, Australie). Possibles allergies rares.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (36, 'fr', 'Carotènes (Bêta-carotène). Colorant orangé naturel et précurseur de la vitamine A. Sans danger et nutritif. Présent dans les carottes et de nombreux légumes.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (38, 'fr', 'Extrait de paprika. Colorant rouge-orangé naturel. Sans danger. Issu des poivrons de paprika. Utilisé dans les fromages et les sauces.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (47, 'fr', 'Rouge de betterave/Bétanine - colorant rouge-violet naturel. Très sûr.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (48, 'fr', 'Anthocyanes. Colorants violet-rouge naturels issus de fruits. Sans danger. Présents dans les baies, le raisin et le chou rouge.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (49, 'fr', 'Carbonate de calcium - colorant blanc, source de calcium. Totalement sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (50, 'fr', 'Dioxyde de titane - colorant blanc. L''EFSA évalue une interdiction pour risques possibles (nanoparticules). La France l''a déjà interdit depuis 2020. ÉVITER.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (51, 'fr', 'Oxydes et hydroxydes de fer - colorants jaune/rouge/noir. Naturels, très sûrs.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (52, 'fr', 'Aluminium - colorant métallique. CONTROVERSÉ (liens avec Alzheimer non prouvés mais prudence recommandée).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (53, 'fr', 'Argent - utilisé pour la décoration alimentaire. Coûteux, inerte, non toxique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (54, 'fr', 'Or - utilisé pour la décoration alimentaire. Totalement inerte.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (55, 'fr', 'Lithol Rubine BK/Pigment Rubis - colorant rouge synthétique. Uniquement pour la croûte des fromages. Utilisation limitée et spécifique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (57, 'fr', 'Conservateur courant. Généralement sans danger. Utilisé dans les boissons, les fromages et les produits de boulangerie.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (58, 'fr', 'Sorbate de sodium - sel de l''acide sorbique. Sans danger comme le E200.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (59, 'fr', 'Sorbate de potassium. Conservateur très utilisé. Généralement reconnu comme sûr. Présent dans le vin, le fromage et les viandes séchées.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (60, 'fr', 'Sorbate de calcium - comme E200-202. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (61, 'fr', 'Acide benzoïque. Conservateur naturel présent dans les baies. Peut provoquer des réactions allergiques. Déconseillé aux enfants.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (62, 'fr', 'Peut provoquer des réactions allergiques. À éviter en cas d''asthme. Courant dans les boissons gazeuses.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (63, 'fr', 'Benzoate de potassium - comme E211. Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (64, 'fr', 'Benzoate de calcium - comme E211-212. Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (65, 'fr', 'Éthyl p-hydroxybenzoate (parabène) - conservateur. Possible perturbateur endocrinien. CONTROVERSÉ, limiter l''utilisation.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (66, 'fr', 'Éthyl p-hydroxybenzoate de sodium - comme E214. Parabène, CONTROVERSÉ.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (67, 'fr', 'Propyl p-hydroxybenzoate - conservateur parabène. Possible perturbateur endocrinien. INTERDIT dans l''UE depuis 2006.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (68, 'fr', 'Propyl p-hydroxybenzoate de sodium - parabène. INTERDIT dans l''UE avec le E216.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (69, 'fr', 'Méthyl p-hydroxybenzoate - parabène. Moins controversé que E214-217 mais prudence recommandée.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (70, 'fr', 'Méthyl p-hydroxybenzoate de sodium - comme E218.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (71, 'fr', 'Sulfites - peuvent provoquer des réactions chez les asthmatiques. Utilisés dans le vin et les fruits secs.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (72, 'fr', 'Sulfite de sodium. Peut déclencher des crises d''asthme. Détruit la vitamine B1. Courant dans le vin et les fruits secs.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (73, 'fr', 'Bisulfite de sodium - sulfite. Risque d''allergies/asthme.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (74, 'fr', 'Métabisulfite de sodium - sulfite courant dans le vin. Prudence pour les asthmatiques et les allergiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (75, 'fr', 'Métabisulfite de potassium - sulfite utilisé dans le vin. Prudence pour les asthmatiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (76, 'fr', 'Sulfite de potassium - conservateur sulfité. Comme E220-224, prudence pour les asthmatiques. Détruit la vitamine B1.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (77, 'fr', 'Sulfite de calcium - conservateur. Prudence pour les asthmatiques, peut provoquer des réactions respiratoires sévères.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (78, 'fr', 'Hydrogénosulfite de calcium - conservateur sulfité. Risque d''allergies et d''asthme comme les autres sulfites.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (79, 'fr', 'Bisulfite de potassium - conservateur sulfité utilisé dans le vin. Prudence pour les asthmatiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (80, 'fr', 'Biphényle/Diphényle - conservateur pour agrumes (sur la peau). TRÈS TOXIQUE en cas d''ingestion. Toujours laver les fruits traités. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (81, 'fr', 'Orthophénylphénol - fongicide pour peaux d''agrumes. Cancérogène possible. Bien laver les fruits. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (82, 'fr', 'Orthophénylphénate de sodium - comme E231, fongicide pour les peaux. Toujours laver les fruits traités.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (83, 'fr', 'Thiabendazole - fongicide systémique pour fruits. Peut pénétrer la peau. Effets neurologiques possibles. Limiter l''exposition.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (84, 'fr', 'Nisine - bactériostatique naturel issu de la fermentation. Sans danger, utilisé dans les fromages et les conserves.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (85, 'fr', 'Natamycine/Pimaricine - antifongique naturel. Utilisé uniquement en surface des fromages et charcuteries.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (89, 'fr', 'Hexaméthylènetétramine - conservateur synthétique. Peut libérer du formaldéhyde (cancérogène). ÉVITER. Interdit dans de nombreux pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (90, 'fr', 'Formaldéhyde - conservateur. CANCÉROGÈNE AVÉRÉ. INTERDIT dans l''UE pour usage alimentaire.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (91, 'fr', 'Dicarbonate de diméthyle - conservateur pour boissons. Se décompose rapidement en CO2 et méthanol (traces).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (92, 'fr', 'Nitrite de potassium - conservateur pour charcuteries. Comme E250, peut former des nitrosamines cancérogènes. DJA faible, limiter les charcuteries.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (93, 'fr', 'Nitrite de sodium. Utilisé dans les charcuteries. Peut former des composés cancérogènes à haute température. Consommation modérée recommandée.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (94, 'fr', 'Nitrate de sodium. Conservateur dans les charcuteries. Converti en nitrite dans l''organisme. Consommation modérée recommandée.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (95, 'fr', 'Nitrate de potassium. Utilisé dans les charcuteries et les fromages. Peut affecter la tension artérielle. Limiter la consommation.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (96, 'fr', 'Acide acétique - vinaigre. Totalement naturel et sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (97, 'fr', 'Acétate de potassium - régulateur d''acidité. Sel de vinaigre, totalement sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (98, 'fr', 'Acétate de sodium/Diacétate de sodium - régulateur d''acidité et conservateur. Sans danger, issu du vinaigre.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (99, 'fr', 'Acétate de calcium - régulateur d''acidité. Sans danger, apporte aussi du calcium.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (100, 'fr', 'Acétate d''ammonium - régulateur d''acidité. Sans danger pour usage alimentaire.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (101, 'fr', 'Acide lactique. Acide naturel produit par les muscles et par fermentation. Sans danger. Courant dans les aliments et boissons fermentés.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (102, 'fr', 'Acide propionique - conservateur anti-moisissures. Sans danger, également produit par l''organisme.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (103, 'fr', 'Propionate de sodium - comme E280. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (104, 'fr', 'Propionate de calcium - conservateur dans le pain. Sans danger, apporte aussi du calcium.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (106, 'fr', 'Acide borique - conservateur. CONTROVERSÉ : possible toxicité reproductive. Limité ou interdit dans de nombreux pays. ÉVITER.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (107, 'fr', 'Borax/Tétraborate de sodium - conservateur. INTERDIT dans l''UE et de nombreux pays pour toxicité. Ne devrait pas être présent.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (108, 'fr', 'Dioxyde de carbone - CO2. Totalement naturel et sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (109, 'fr', 'Acide malique. Acide naturel présent dans les pommes. Sans danger. Utilisé dans les boissons et les confiseries pour l''acidité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (110, 'fr', 'Acide fumarique. Acide naturel présent dans de nombreuses plantes. Sans danger. Plus acide que l''acide citrique. Utilisé dans les boissons.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (111, 'fr', 'Vitamine C. Antioxydant. Sans danger et bénéfique. Présente dans de nombreux aliments.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (112, 'fr', 'Ascorbate de sodium. Sel de la vitamine C. Antioxydant sans danger. Utilisé dans les charcuteries et les boissons.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (113, 'fr', 'Ascorbate de calcium - vitamine C + calcium. Sans danger et bénéfique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (114, 'fr', 'Ascorbate de potassium - sel de la vitamine C. Sans danger, antioxydant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (115, 'fr', 'Esters d''acides gras de l''acide ascorbique. Antioxydant sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (116, 'fr', 'Extrait riche en tocophérols (Vitamine E). Antioxydant naturel. Sans danger et nutritif. Protège les graisses de l''oxydation.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (117, 'fr', 'Alpha-tocophérol - Vitamine E. Essentiel, puissant antioxydant, sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (118, 'fr', 'Gamma-tocophérol - forme naturelle de la vitamine E. Antioxydant sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (119, 'fr', 'Delta-tocophérol - vitamine E naturelle. Antioxydant sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (120, 'fr', 'Gallate de propyle. Antioxydant synthétique. Peut provoquer des réactions allergiques chez les personnes sensibles. Utilisé dans les graisses et les huiles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (121, 'fr', 'Gallate d''octyle - antioxydant synthétique. CONTROVERSÉ comme E310. Allergies possibles. À limiter.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (122, 'fr', 'Gallate de dodécyle - antioxydant synthétique. CONTROVERSÉ, allergies et troubles possibles. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (123, 'fr', 'Acide érythorbique/Acide isoascorbique - isomère de la vitamine C. Sans danger, moins d''activité vitaminique mais bon antioxydant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (124, 'fr', 'Érythorbate de sodium - sel de l''acide érythorbique. Sans danger, antioxydant courant dans les charcuteries.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (125, 'fr', 'TBHQ (tert-butylhydroquinone) - puissant antioxydant synthétique. CONTROVERSÉ : possibles effets sur l''ADN, hyperactivité. Interdit au Japon, restrictions dans l''UE. À limiter.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (126, 'fr', 'BHA (Hydroxyanisole butylé). Antioxydant CONTROVERSÉ. Certaines études suggèrent des risques potentiels pour la santé. Interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (127, 'fr', 'BHT (Hydroxytoluène butylé). Antioxydant synthétique. Innocuité débattue. Peut provoquer des réactions allergiques. Utilisé dans les graisses et les céréales.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (128, 'fr', 'Lécithine. Émulsifiant naturel issu du soja ou des œufs. Sans danger et bénéfique. Contient de la choline. Très largement utilisé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (129, 'fr', 'Lactate de sodium. Sel de l''acide lactique. Sans danger. Utilisé dans les produits carnés et les fromages. Agit comme conservateur et humectant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (130, 'fr', 'Lactate de potassium - sel de l''acide lactique. Sans danger, utilisé dans les boissons pour sportifs.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (131, 'fr', 'Lactate de calcium - apporte du calcium. Sans danger, utilisé dans les compléments alimentaires et les aliments.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (132, 'fr', 'Lactate d''ammonium - régulateur d''acidité. NON AUTORISÉ DANS L''UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (133, 'fr', 'Lactate de magnésium - apporte du magnésium. NON AUTORISÉ DANS L''UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (134, 'fr', 'Acide citrique. Acidifiant naturel. Généralement sans danger. Courant dans les boissons.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (135, 'fr', 'Citrates de sodium. Sels de l''acide citrique. Sans danger. Utilisés comme régulateur d''acidité dans les boissons et les confitures.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (136, 'fr', 'Citrate de potassium - sel de l''acide citrique. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (137, 'fr', 'Citrate de calcium - source de calcium. Sans danger et bénéfique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (138, 'fr', 'Acide tartrique - acide naturel issu du raisin. Sans danger, utilisé dans le vin et les confiseries.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (139, 'fr', 'Tartrate de sodium - sel de l''acide tartrique. Sans danger, régulateur d''acidité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (140, 'fr', 'Tartrate de potassium/Crème de tartre - sel de l''acide tartrique. Sans danger, levure naturelle.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (141, 'fr', 'Tartrate double de sodium et de potassium/Sel de Seignette - double sel. Sans danger, utilisé en pâtisserie.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (142, 'fr', 'Acide phosphorique. Acidifiant dans les boissons au cola. Une consommation excessive peut affecter l''absorption du calcium. Contribue à l''érosion de l''émail dentaire.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (152, 'fr', 'Phosphate de magnésium - régulateur d''acidité, source de magnésium. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (153, 'fr', 'Malate de sodium - sel de l''acide malique. Sans danger, régulateur d''acidité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (154, 'fr', 'Malate de potassium - sel de l''acide malique. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (155, 'fr', 'Malate de calcium - sel de l''acide malique. Sans danger, source de calcium.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (156, 'fr', 'Acide métatartrique - dérivé de l''acide tartrique. Sans danger, stabilisant pour le vin.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (157, 'fr', 'Tartrate de calcium - sel de l''acide tartrique. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (158, 'fr', 'Acide adipique - acidifiant synthétique. Sans danger, utilisé dans les boissons et les levures chimiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (159, 'fr', 'Adipate de sodium - sel de l''acide adipique. Sans danger, régulateur d''acidité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (160, 'fr', 'Adipate de potassium - sel de l''acide adipique. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (161, 'fr', 'Acide succinique - acide organique naturel. Sans danger, présent dans l''organisme (cycle de Krebs). Utilisé comme exhausteur de goût.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (162, 'fr', 'Fumarate de sodium - sel de l''acide fumarique. Réactions possibles chez les personnes sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (163, 'fr', 'Fumarate de potassium - sel de l''acide fumarique. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (164, 'fr', 'Fumarate de calcium - sel de l''acide fumarique. Sans danger, source de calcium.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (165, 'fr', '1,4-Heptonolactone - acidifiant. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (166, 'fr', 'Acide nicotinique/Niacine - Vitamine B3. Essentielle, très sûre. Utilisée comme agent d''enrichissement.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (167, 'fr', 'Citrate de triammonium - sel de l''acide citrique. Sans danger, régulateur d''acidité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (168, 'fr', 'Citrate de fer ammoniacal - sel de fer. Source de fer. Réactions possibles chez les personnes sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (169, 'fr', 'EDTA calcio-disodique - séquestrant (lie les métaux). Sans danger, prévient l''oxydation et le rancissement.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (170, 'fr', 'Acide alginique. Épaississant naturel issu d''algues. Sans danger. Utilisé dans les glaces et les gelées. Peut inhiber l''absorption de nutriments en grande quantité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (171, 'fr', 'Alginate de sodium. Épaississant naturel issu d''algues. Sans danger. Courant dans les glaces et les puddings instantanés.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (172, 'fr', 'Alginate de potassium - issu d''algues. Sans danger, épaississant et gélifiant naturel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (173, 'fr', 'Alginate d''ammonium - issu d''algues. Sans danger, agent gélifiant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (174, 'fr', 'Alginate de calcium - issu d''algues. Sans danger, utilisé en gastronomie moléculaire (sphérification).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (175, 'fr', 'Alginate de propylène glycol - algue modifiée. Sans danger, émulsifiant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (176, 'fr', 'Agar-agar - gélifiant naturel issu d''algues rouges. Très sûr, riche en fibres. Également utilisé comme laxatif naturel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (177, 'fr', 'Carraghénanes. Épaississant naturel issu d''algues rouges. Innocuité débattue - certaines études suggèrent des troubles digestifs. Utilisé dans les produits laitiers.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (180, 'fr', 'Gomme de caroube. Épaississant naturel issu du caroubier. Sans danger. Utilisée dans les glaces et les produits de boulangerie.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (181, 'fr', 'Gomme de guar. Épaississant naturel issu des graines de guar. Sans danger en quantités normales. Peut causer des troubles digestifs en grande quantité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (182, 'fr', 'Gomme adragante - résine naturelle issue d''arbustes. Sans danger, épaississant traditionnel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (183, 'fr', 'Gomme d''acacia (Gomme arabique). Épaississant naturel issu d''acacias. Sans danger. Utilisé en confiserie et dans les boissons.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (184, 'fr', 'Gomme xanthane. Polysaccharide microbien. Sans danger. Excellent épaississant et stabilisant. Utilisé dans les produits sans gluten.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (185, 'fr', 'Gomme karaya - résine naturelle issue d''arbres. Sans danger, épaississant. Possibles allergies rares.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (186, 'fr', 'Gomme de tara - issue de graines. Sans danger, épaississant naturel similaire à la gomme de caroube.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (187, 'fr', 'Gomme gellane - issue de fermentation bactérienne. Sans danger, puissant agent gélifiant. Utilisée dans les alternatives végétales.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (188, 'fr', 'Sorbitol. Polyol (sucre-alcool). Peut avoir un effet laxatif en grande quantité. Utilisé dans les produits sans sucre. Généralement sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (189, 'fr', 'Mannitol. Polyol (sucre-alcool). Peut avoir un effet laxatif. Utilisé dans les chewing-gums et les produits pour diabétiques. Généralement sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (190, 'fr', 'Glycérol/Glycérine - humectant naturel. Totalement sans danger, également produit par l''organisme. Peut être d''origine végétale ou animale.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (191, 'fr', 'Hémicellulose de soja - fibre issue du soja. Sans danger, prébiotique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (192, 'fr', 'Polyoxyéthylène (8) stéarate - émulsifiant synthétique. NON AUTORISÉ DANS L''UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (193, 'fr', 'Polyoxyéthylène (40) stéarate - émulsifiant. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (194, 'fr', 'Polysorbate 20/Monolaurate de polyoxyéthylène sorbitane - émulsifiant synthétique. Généralement sans danger, possibles allergies rares.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (195, 'fr', 'Polysorbate 80/Monooléate de polyoxyéthylène sorbitane - émulsifiant courant. Généralement sans danger mais des études récentes suggèrent la prudence avec le microbiote intestinal. Modération.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (196, 'fr', 'Polysorbate 40 - émulsifiant. Utilisé dans les glaces. Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (197, 'fr', 'Polysorbate 60 - émulsifiant. Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (198, 'fr', 'Polysorbate 65 - émulsifiant. Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (201, 'fr', 'Gélatine - protéine issue d''os/peau/cartilage animaux (porc/bœuf). NON VÉGAN. NON HALAL (si porc). Neutre pour la santé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (202, 'fr', 'Phosphatides d''ammonium - émulsifiant issu de la lécithine. Sans danger, utilisé dans le chocolat.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (203, 'fr', 'Isobutyrate d''acétate de saccharose - émulsifiant dans les boissons. Sans danger selon l''EFSA, interdit dans certains pays.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (204, 'fr', 'Esters glycériques de résine de bois - émulsifiant issu du pin. Sans danger, utilisé dans les boissons aux agrumes.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (205, 'fr', 'Diphosphates (sodium/potassium/calcium) - régulateurs d''acidité et émulsifiants. Sans danger MAIS l''excès de phosphates est problématique pour les reins. Présents dans de nombreux aliments transformés. LIMITER.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (206, 'fr', 'Triphosphates - émulsifiants et stabilisants dans les charcuteries/fromages. Comme E450, limiter l''excès de phosphates.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (207, 'fr', 'Polyphosphates - puissants émulsifiants. Comme E450-451, l''EXCÈS est problématique. Courants dans les aliments transformés. MODÉRATION.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (208, 'fr', 'Bêta-cyclodextrine - dérivé d''amidon. Sans danger, utilisé pour encapsuler les arômes.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (212, 'fr', 'Méthylcellulose - dérivé de cellulose. Sans danger, épaississant et laxatif naturel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (213, 'fr', 'Éthylcellulose - dérivé de cellulose. Sans danger, agent filmogène.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (214, 'fr', 'Hydroxypropylcellulose - dérivé de cellulose. Sans danger, épaississant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (215, 'fr', 'Hydroxypropylméthylcellulose/HPMC - dérivé de cellulose. Sans danger, capsule végétale pour compléments alimentaires.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (216, 'fr', 'Éthylméthylcellulose - dérivé de cellulose. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (217, 'fr', 'Carboxyméthylcellulose - dérivé de cellulose. Sans danger, épaississant courant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (218, 'fr', 'Carboxyméthylcellulose sodique réticulée - cellulose modifiée. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (219, 'fr', 'Carboxyméthylcellulose hydrolysée enzymatiquement - cellulose modifiée. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (222, 'fr', 'Mono- et diglycérides d''acides gras. Émulsifiant courant. Généralement sans danger. Peut être d''origine animale ou végétale.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (227, 'fr', 'Esters monoacétyltartriques et diacétyltartriques. Émulsifiant utilisé dans le pain. Généralement sans danger. Améliore la force de la pâte.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (243, 'fr', 'Carbonates de sodium. Régulateur d''acidité et agent levant. Sans danger. Courant dans les produits de boulangerie. Aussi connu comme bicarbonate de soude.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (245, 'fr', 'Carbonates d''ammonium. Agent levant pour produits de boulangerie. Sans danger - s''évapore à la cuisson. Utilisé dans les biscuits et les crackers.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (279, 'fr', 'Dioxyde de silicium. Anti-agglomérant. Généralement sans danger. Présent dans les aliments en poudre. Empêche la formation de grumeaux.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (280, 'fr', 'Silicate de calcium. Anti-agglomérant. Sans danger. Utilisé dans les aliments en poudre et en granulés.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (297, 'fr', 'Acide glutamique. Acide aminé naturel. Exhausteur de goût. Généralement sans danger mais peut provoquer des réactions de sensibilité au MSG chez certaines personnes.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (298, 'fr', 'Glutamate monosodique (MSG). Exhausteur de goût CONTROVERSÉ. Peut provoquer des maux de tête et des bouffées de chaleur chez les personnes sensibles. Très utilisé dans la cuisine asiatique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (299, 'fr', 'Glutamate monopotassique. Exhausteur de goût similaire au MSG. Peut provoquer des réactions chez les personnes sensibles. Utilisé dans les aliments transformés.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (300, 'fr', 'Glutamate de calcium - exhausteur de goût. Comme E621-622.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (301, 'fr', 'Glutamate monoammonique - exhausteur de goût. Comme le MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (302, 'fr', 'Glutamate de magnésium - exhausteur de goût. Comme le MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (303, 'fr', 'Acide guanylique - nucléotide naturel. Sans danger, rehausse la saveur umami. Souvent associé au MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (304, 'fr', 'Guanylate disodique. Exhausteur de goût souvent associé au MSG. Issu de poisson ou de levure. Non adapté aux personnes souffrant de goutte.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (305, 'fr', 'Guanylate dipotassique - sel de l''acide guanylique. Sans danger, exhausteur de goût.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (306, 'fr', 'Guanylate de calcium - exhausteur de goût. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (307, 'fr', 'Acide inosinique - nucléotide naturel issu de viande/poisson. Sans danger, saveur umami.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (308, 'fr', 'Inosinate disodique. Exhausteur de goût souvent associé au MSG. Peut déclencher la goutte. Issu de viande ou de poisson.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (309, 'fr', 'Inosinate dipotassique - exhausteur de goût. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (310, 'fr', 'Inosinate de calcium - exhausteur de goût. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (311, 'fr', '5''-ribonucléotides de calcium - mélange E626+E630. Sans danger, puissant exhausteur de goût.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (312, 'fr', '5''-ribonucléotides disodiques - mélange guanylate+inosinate. Très utilisé, sans danger. Potentialise le MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (316, 'fr', 'Cire d''abeille - enrobage naturel pour fruits et confiseries. Sans danger, naturel. NON VÉGAN.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (317, 'fr', 'Cire de candelilla - cire végétale issue d''une plante mexicaine. Sans danger, végan.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (318, 'fr', 'Cire de carnauba - issue d''un palmier brésilien. Sans danger, cire naturelle la plus dure. Agent d''enrobage.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (319, 'fr', 'Shellac - résine issue d''insectes (Lac). Sans danger pour les enrobages. NON VÉGAN.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (320, 'fr', 'Paraffine/Cire microcristalline - issue du pétrole raffiné. Sans danger pour les enrobages, non absorbée.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (322, 'fr', 'Esters d''acide montanique - cire synthétique. Sans danger, agent d''enrobage.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (323, 'fr', 'Cire de polyéthylène oxydée - cire synthétique. Sans danger, enrobage.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (324, 'fr', 'L-cystéine - acide aminé naturel. Sans danger, améliorant de farine. Souvent issu de plumes/cheveux (non végan) ou de fermentation (végan).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (333, 'fr', 'Argon - gaz noble inerte. Sans danger, utilisé comme gaz protecteur dans les emballages.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (334, 'fr', 'Hélium - gaz noble. Sans danger, rarement utilisé dans l''alimentation.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (335, 'fr', 'Azote - gaz inerte. Sans danger, utilisé dans les emballages et la crème chantilly.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (336, 'fr', 'Protoxyde d''azote - gaz hilarant. Sans danger pour usage alimentaire (crème chantilly). Ne pas inhaler directement.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (339, 'fr', 'Propane - gaz. Sans danger comme propulseur.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (340, 'fr', 'Oxygène - gaz. Sans danger, rarement utilisé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (341, 'fr', 'Hydrogène - gaz. Sans danger.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (342, 'fr', 'Acésulfame K. Édulcorant artificiel. 200 fois plus sucré que le sucre. Généralement reconnu comme sûr. Stable à la chaleur.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (343, 'fr', 'Aspartame. Édulcorant artificiel. CONTROVERSÉ. Contient de la phénylalanine - dangereux pour les patients atteints de phénylcétonurie. À éviter en cas de sensibilité.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (344, 'fr', 'Cyclamate. Édulcorant artificiel. Interdit aux États-Unis depuis 1969. Autorisé dans l''UE mais CONTROVERSÉ. 30 à 50 fois plus sucré que le sucre.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (345, 'fr', 'Saccharine. Premier édulcorant artificiel. 300 à 500 fois plus sucré que le sucre. Sans danger en quantités modérées. Arrière-goût métallique.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (346, 'fr', 'Sucralose. Édulcorant artificiel dérivé du sucre. 600 fois plus sucré que le sucre. Stable à la chaleur. Généralement reconnu comme sûr.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (347, 'fr', 'Thaumatine - protéine sucrée issue d''un fruit africain. 2000 fois plus sucré que le sucre. Très sûr, naturel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (348, 'fr', 'Néohespéridine DC - édulcorant issu d''agrumes. 1000 fois plus sucré. Sans danger, naturel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (349, 'fr', 'Sel d''aspartame-acésulfame - mélange E951+E950. Sans danger (avec les mêmes précautions que l''aspartame).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (350, 'fr', 'Maltitol. Polyol (sucre-alcool). Environ 75-90% du pouvoir sucrant du sucre. Peut avoir un effet laxatif. Utilisé dans les produits sans sucre.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (351, 'fr', 'Lactitol - polyol issu du lactose. Sans danger, prébiotique. Possible effet laxatif.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (352, 'fr', 'Xylitol. Polyol issu du bouleau. Prévient les caries dentaires. Peut causer des troubles digestifs en grande quantité. Sans danger pour les diabétiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (353, 'fr', 'Érythritol - polyol à zéro calorie. Très sûr, mieux toléré que les autres polyols. Pas d''effet laxatif.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (354, 'fr', 'Extrait de quillaia - saponine issue de l''écorce d''un arbre sud-américain. Sans danger, agent moussant naturel dans les boissons.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (355, 'fr', 'Invertase - enzyme issue de levure. Sans danger, hydrolyse le saccharose. Utilisée dans la production de miel artificiel.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (356, 'fr', 'Lysozyme - enzyme antibactérienne issue du blanc d''œuf. Sans danger MAIS issu d''œufs (NON VÉGAN). Allergies possibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (357, 'fr', 'Polydextrose - fibre soluble synthétique. Sans danger, prébiotique. Léger effet laxatif.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (358, 'fr', 'Polyvinylpyrrolidone/PVP - polymère synthétique. Sans danger, stabilisant dans les boissons et les produits pharmaceutiques.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (359, 'fr', 'Polyvinylpolypyrrolidone - polymère. Sans danger, stabilisant dans le vin et la bière.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (379, 'fr', 'Citrate de triéthyle - ester. Sans danger, solvant et stabilisant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (381, 'fr', 'Diacétate de glycéryle/Diacétine - issu du glycérol. Sans danger, solvant et humectant.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (382, 'fr', 'Triacétate de glycéryle/Triacétine - issu du glycérol. Sans danger, solvant d''arômes.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (384, 'fr', 'Propylène glycol/Propane-1,2-diol - alcool. Sans danger, humectant et solvant. Très utilisé.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (385, 'fr', 'Pectine. Gélifiant naturel issu de fruits. Sans danger et bénéfique. Contient des fibres solubles. Utilisée dans les confitures et les gelées.');
